#include <iostream>
#include <iomanip>
#include <cmath>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    double sum_cos = 0.0, sum_sin = 0.0;
    double product = 1.0;

    for (int k = 1; k <= n; ++k) {
        sum_cos += cos(k);
        sum_sin += sin(k);
        // For n >= 1, sum_sin should not be zero for the given range,
        // but guard just in case:
        if (sum_sin != 0.0) {
            product *= sum_cos / sum_sin;
        }
    }

    cout << fixed << setprecision(3) << product << "\n";

    return 0;
}
